actionConfiguration.body:
mutation updateSubscriptionPartnerPriceAndPeriodicityByStaff(
	$userId: String!,
	$recurrentSubscriptionId: String!,
	$price: Float!,
	$periodicity: String!,
	$partnerId: Float,
	$coverLevel: String,
) {
	updateSubscriptionPartnerPriceAndPeriodicityByStaff (
		userId: $userId, 
		recurrentSubscriptionId: $recurrentSubscriptionId, 
		price: $price, 
		periodicity: $periodicity,
		partnerId: $partnerId,
		coverLevel: $coverLevel,
	) {
		id
	}
}

